//vip.opstream12.com/20220327/6051_ecab1b1d/index.m3u8"}]}],"description":"<p>Nhà văn ngôn tình hạng ba Lý Xuân Hỷ (Gia Trạch đóng) đột nhiên bị tai nạn xe. Sau khi tỉnh dậy phát hiện mình trở thành Tiền Trăn Trăn (Châu Lệ Lam đóng). Cô ấy không chỉ bị mất trí nhớ mà còn hay bị chi phối bởi những lời bộc bạch khó hiểu, thực hiện những hành động như một \\\"trà xanh\\\" dụ dỗ ông chủ Âu Dương Thần (Lâu Minh đóng). Âu Dương Thần theo đuổi Tiền Trăn Trăn theo cách của một tổng tài bá đạo, nhưng chàng trợ lý nhỏ Lục Ly (Trương Mạnh đóng) dần dần chiếm vị trí quan trọng trong lòng Tiền Trăn Trăn. Thế nhưng một Lục Ly nhìn có vẻ rất đơn thuần lại mang trong mình hai thân phận...</p>","tmdb_id":113277,"_supabaseOriginalSlug":"nguoi-tinh-vuot-thoi-gian","_supabaseExportEpisodesOnly":false,"_id":"6240639dc78eb57bbfe24747","time":"30M27S","tmdb":{"type":"tv","id":"113277","season":1,"vote_average":8,"vote_count":1},"_image_preserved":true},{"id":"624063c7c78eb57bbfe24782","_id":"624063c7c78eb57bbfe24782","title":"This is Youth","origin_name":"This is Youth","slug":"this-is-youth","year":2020,"type":"series","genre":[{"id":"620a220de0fc277084dfd16d","name":"Tình Cảm","slug":"tinh-cam"}],"country":[{"id":"62093063196e9f4ab6b448b8","name":"Trung Quốc","slug":"trung-quoc"}],"lang_key":"Vietsub","episode_current":"Hoàn Tất (12/12)","quality":"HD","is_4k":false,"is_exclusive":false,"status":"completed","showtimes":"","chieurap":false,"sub_docquyen":false,"episodes":[{"server_name":"Vietsub #1","is_ai":false,"server_data":[{"name":"1","slug":"1","filename":"this-is-youth-tap-1","link_embed":"https://vip.opstream12.com/share/80c0e8c4457441901351e4abbcf8c75c","link_m3u8":"https://vip.opstream12.com/20220327/6099_10b87e5f/index.m3u8"},{"name":"2","slug":"2","filename":"this-is-youth-tap-2","link_embed":"https://vip.opstream12.com/share/802a5fd4efb36391dfa8f1991fd0f849","link_m3u8":"https://vip.opstream12.com/20220327/6100_9b0d9923/index.m3u8"},{"name":"3","slug":"3","filename":"this-is